import { useParams, useNavigate, useLocation } from 'react-router-dom'
import styles from './DashboardLevel2.module.css'
import { FiArrowLeft } from 'react-icons/fi'

import imageLinkUp from "../../assets/images/link_up_image2.png"
import { useContext, useEffect, useState } from 'react'
import AppContext from '../../context'
import { DashboardLevel1Entity, DashboardLevel2Entity } from '../../entities/DashboardEntity'
import { DashboardRealtimeService, DashboardService } from '../../services/dashboard'
import { AlertEntity } from '../../layouts/Alert/AlertEntity'
import { formatDate } from 'date-fns'
import { TbRefreshDot } from 'react-icons/tb'
import { LinkUpEntity } from '../../entities/LinkUpEntity'
import { LinkUpService } from '../../services/link_up'
import { DashboardFollErrService } from '../../services/following_error'
import { DashboardFollowingLevel2 } from '../../entities/FollowingErrorEntity'
import { DashboardCenterlineLevel2 } from '../../entities/CenterlineEntity'
import { DashboardCenterlineService } from '../../services/centerline'

export default function DashboardV2() {
    // ========================================= GLOBAL CONTEXT =========================================  //
    const context = useContext(AppContext)
    const contextVersion = context.version
    const contextAccessToken = context.contextAccessToken
    const contextShowAlertFunc = context.contextShowAlertFunc
    const contextShowLoadingFunc = context.contextShowLoadingFunc
    const stateShowLoading = context.stateShowLoading
    const navigate = useNavigate()
    const location = useLocation()
    // ========================================= GLOBAL CONTEXT =========================================  //


    // ========================================= STATE VIEW =========================================  //
    const { businessUnitId } = useParams()
    const { business_unit } = location.state || {}

    interface DashboardLevel1State {
        business_unit_id: number,
        business_unit: string,

        ool_pressure: number,
        ool_vibration: number,
        ool_temperature: number,
        machine_ool_pressure: number[],
        machine_ool_vibration: number[],

        centerline_green: number
        centerline_yellow: number
        centerline_red: number
        machine_ool_centerline: number[],

        ool_following_error: number,
        machine_ool_following_error: number[],

        machine_ool: number[]
    }
    const [level1Data, setLevel1Data] = useState<DashboardLevel1State>({
        business_unit_id: business_unit.business_unit_id,
        business_unit: business_unit.business_unit,
        ool_pressure: 0,
        ool_vibration: 0,
        ool_temperature: 0,
        machine_ool_pressure: [],
        machine_ool_vibration: [],
        centerline_green: 0,
        centerline_yellow: 0,
        centerline_red: 0,
        machine_ool_centerline: [],
        ool_following_error: 0,
        machine_ool_following_error: [],
        machine_ool: [],
    })

    const cache = (() => {
        const cache = localStorage.getItem("cache")
        if (cache == null) {
            return { start_date: new Date(), end_date: new Date(), isRealtime: true }
        } else {
            const data = JSON.parse(cache)
            return {
                start_date: data.start_date,
                end_date: data.end_date,
                isRealtime: data.isRealtime,
            }
        }
    })()

    interface FilterType { start_date: Date; end_date: Date; }
    const [filterDate, setFilterDate] = useState<FilterType>({
        start_date: cache.start_date,
        end_date: cache.end_date
    })

    const [isRealtime, setIsRealtime] = useState<boolean>(cache.isRealtime ?? true)

    const [luData, setLuData] = useState<LinkUpEntity[]>([])
    const [tableData, setTableData] = useState<{ [id: string]: DashboardLevel2Entity | undefined }>({})
    const [tableDataFoll, setTableDataFoll] = useState<{ [id: string]: DashboardFollowingLevel2 | undefined }>({})
    const [tableDataCenterline, setTableDataCenterline] = useState<{ [id: string]: DashboardCenterlineLevel2 | undefined }>({})
    // ========================================= STATE VIEW =========================================  //


    // ========================================= FUNCTIONS =========================================  //
    const handleToggle = () => {
        setIsRealtime((prev) => !prev)
    }

    const generateDataLu = async () => {
        if (luData.length == 0) { contextShowLoadingFunc(true) }
        try {
            const resp = await LinkUpService.GetAllLinkUp(businessUnitId)
            setLuData(resp)
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3, }))
        } finally {
            if (luData.length == 0) { contextShowLoadingFunc(false) }
        }
    }

    const generateDataServer = async () => {
        try {
            if (businessUnitId) {
                let resp: DashboardLevel2Entity[] = []
                if (isRealtime) {
                    resp = await DashboardRealtimeService.GetDashboardLevel2(Number(businessUnitId))
                    setFilterDate({ start_date: new Date(), end_date: new Date() })
                    localStorage.removeItem("cache")
                } else {
                    const start_date = formatDate(filterDate.start_date, 'yyyy-MM-dd')
                    const end_date = formatDate(filterDate.end_date, 'yyyy-MM-dd')

                    resp = await DashboardService.GetDashboardLevel2(Number(businessUnitId), start_date, end_date)
                    localStorage.setItem("cache", JSON.stringify({ ...filterDate, isRealtime }))
                }

                const data: { [id: string]: DashboardLevel2Entity } = {}
                const newBuData: DashboardLevel1State = { ...level1Data, ool_pressure: 0, ool_temperature: 0, ool_vibration: 0 }
                for (let i = 0; i < resp.length; i++) {
                    const row = resp[i]
                    data[`${row.link_up_id}`] = row

                    if (newBuData.machine_ool_pressure == undefined) {
                        newBuData.machine_ool_pressure = []
                    }
                    if (newBuData.machine_ool_vibration == undefined) {
                        newBuData.machine_ool_vibration = []
                    }

                    newBuData.ool_pressure = (newBuData.ool_pressure ?? 0) + row.ool_pressure
                    newBuData.ool_vibration = (newBuData.ool_vibration ?? 0) + row.ool_vibration
                    newBuData.ool_temperature = (newBuData.ool_temperature ?? 0) + row.ool_temperature
                    newBuData.machine_ool_pressure = newBuData.machine_ool_pressure.concat(row.machine_ool_pressure)
                    newBuData.machine_ool_vibration = newBuData.machine_ool_vibration.concat(row.machine_ool_vibration)
                }
                newBuData.machine_ool = Array.from(new Set(newBuData.machine_ool))

                setLevel1Data((prev) => ({
                    ...prev,
                    ool_pressure: newBuData.ool_pressure,
                    ool_vibration: newBuData.ool_vibration,
                    ool_temperature: newBuData.ool_temperature,
                    machine_ool_pressure: newBuData.machine_ool_pressure,
                    machine_ool_vibration: newBuData.machine_ool_vibration,
                }))
                setTableData(data)
            }
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        }
    }

    const generateDataFollErr = async () => {
        try {
            if (businessUnitId) {
                let resp: DashboardFollowingLevel2[] = []
                if (isRealtime) {
                    resp = await DashboardFollErrService.DashboardLevel2Realtime(Number(businessUnitId))
                    setFilterDate({ start_date: new Date(), end_date: new Date() })
                    localStorage.removeItem("cache")
                } else {
                    const start_date = formatDate(filterDate.start_date, 'yyyy-MM-dd')
                    const end_date = formatDate(filterDate.end_date, 'yyyy-MM-dd')

                    resp = await DashboardFollErrService.DashboardLevel2(start_date, end_date, Number(businessUnitId))
                    localStorage.setItem("cache", JSON.stringify({ ...filterDate, isRealtime }))
                }

                const data: { [id: string]: DashboardFollowingLevel2 } = {}
                const newBuData: DashboardLevel1State = { ...level1Data, ool_following_error: 0 }
                for (let i = 0; i < resp.length; i++) {
                    const row = resp[i]
                    data[`${row.link_up_id}`] = row

                    if (newBuData.machine_ool_following_error == undefined) {
                        newBuData.machine_ool_following_error = []
                    }

                    newBuData.ool_following_error = (newBuData.ool_following_error ?? 0) + row.ool_following_error
                    newBuData.machine_ool_following_error = newBuData.machine_ool_following_error.concat(row.machine_ool_following_error)
                }

                newBuData.machine_ool = Array.from(new Set(newBuData.machine_ool))

                setLevel1Data((prev) => ({
                    ...prev,
                    ool_following_error: newBuData.ool_following_error,
                    machine_ool_following_error: newBuData.machine_ool_following_error,
                }))
                setTableDataFoll(data)
            }
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3, }))
        }
    }

    const generateDataCenterline = async () => {
        try {
            if (businessUnitId) {
                let resp: DashboardCenterlineLevel2[] = []
                if (isRealtime) {
                    resp = await DashboardCenterlineService.DashboardLevel2Realtime(Number(businessUnitId))
                    setFilterDate({ start_date: new Date(), end_date: new Date() })
                    localStorage.removeItem("cache")
                } else {
                    const start_date = formatDate(filterDate.start_date, 'yyyy-MM-dd')
                    const end_date = formatDate(filterDate.end_date, 'yyyy-MM-dd')

                    resp = await DashboardCenterlineService.DashboardLevel2(start_date, end_date, Number(businessUnitId))
                    localStorage.setItem("cache", JSON.stringify({ ...filterDate, isRealtime }))
                }

                const data: { [id: string]: DashboardCenterlineLevel2 } = {}
                const newBuData: DashboardLevel1State = { ...level1Data, centerline_green: 0, centerline_yellow: 0, centerline_red: 0 }
                for (let i = 0; i < resp.length; i++) {
                    const row = resp[i]
                    data[`${row.link_up_id}`] = row

                    if (newBuData.machine_ool_centerline == undefined) {
                        newBuData.machine_ool_centerline = []
                    }

                    newBuData.centerline_green = (newBuData.centerline_green ?? 0) + row.centerline_green
                    newBuData.centerline_yellow = (newBuData.centerline_yellow ?? 0) + row.centerline_yellow
                    newBuData.centerline_red = (newBuData.centerline_red ?? 0) + row.centerline_red
                    newBuData.machine_ool_centerline = newBuData.machine_ool_centerline.concat(row.centerline_id_ool)
                }

                newBuData.machine_ool = Array.from(new Set(newBuData.machine_ool))

                setLevel1Data((prev) => ({
                    ...prev,
                    centerline_green: newBuData.centerline_green,
                    centerline_yellow: newBuData.centerline_yellow,
                    centerline_red: newBuData.centerline_red,
                    machine_ool_centerline: newBuData.machine_ool_centerline,
                }))
                setTableDataCenterline(data)
            }
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3, }))
        }
    }

    const generateData = async () => {
        if (isRealtime) {
            if (contextVersion.server != undefined) { await generateDataServer() }
            if (contextVersion.centerline != undefined) { await generateDataCenterline() }
            if (contextVersion.following != undefined) { await generateDataFollErr() }
            setLevel1Data((prev) => {
                const merged = [
                    ...prev.machine_ool_vibration, ...prev.machine_ool_pressure,
                    ...prev.machine_ool_centerline, ...prev.machine_ool_following_error,
                ]
                const machine_ool = Array.from(new Set(merged))
                return { ...prev, machine_ool }
            })
        } else {
            resetAllData()
            contextShowLoadingFunc(true)
            // langsung tampilkan ketika udah ada yg selesai satu
            const promise = []
            if (contextVersion.server != undefined) { promise.push(generateDataServer()) }
            if (contextVersion.centerline != undefined) { promise.push(generateDataCenterline()) }
            if (contextVersion.following != undefined) { promise.push(generateDataFollErr()) }
            try { await Promise.any(promise) } catch { }

            // TODO
            setLevel1Data((prev) => {
                const merged = [
                    ...prev.machine_ool_vibration, ...prev.machine_ool_pressure,
                    ...prev.machine_ool_centerline, ...prev.machine_ool_following_error,
                ]
                const machine_ool = Array.from(new Set(merged))
                return { ...prev, machine_ool }
            })

            contextShowLoadingFunc(false)
        }
    }

    const resetAllData = () => {
        setLevel1Data((prev) => ({
            ...prev,
            ool_pressure: 0,
            ool_vibration: 0,
            ool_temperature: 0,
            machine_ool_pressure: [],
            machine_ool_vibration: [],
            ool_following_error: 0,
            machine_ool_following_error: [],
            machine_ool: [],
        }))
        setTableData({})
        setTableDataFoll({})
    }

    const getStatusOOL = (value: number | undefined, item: LinkUpEntity) => {
        const ool = value ?? 0
        let result = ''
        if (ool > item.link_up_warn) {
            result = styles.warningBackground
        }
        if (ool > item.link_up_alarm) {
            result = styles.dangerBackground
        }
        return result
    }

    const getStatusOOLCenterline = (value: number | undefined, item: DashboardCenterlineLevel2) => {
        if (item.centerline_alarm == null || item.centerline_warn == null) {
            return styles.runningBackground
        }

        const oolPressure = value ?? 0
        let result = styles.runningBackground
        if (oolPressure > item.centerline_warn) {
            result = styles.warningBackground
        }
        if (oolPressure > item.centerline_alarm) {
            result = styles.dangerBackground
        }
        return result
    }

    useEffect(() => {
        generateData()
        if (isRealtime) {
            const interval = setInterval(generateData, 2000)

            return () => {
                clearInterval(interval)
            }
        }
    }, [contextAccessToken, isRealtime, businessUnitId])

    // generate once
    useEffect(() => {
        generateDataLu()
    }, [])
    // ========================================= FUNCTIONS =========================================  //

    return (
        <div className='container'>
            {/* Header */}
            <div className={styles.cardHeader}>
                <div className={styles.leftMidWrapper}>
                    <div className={styles.leftSection}>
                        <button className={styles.backButton} onClick={() => navigate(-1)}>
                            <FiArrowLeft size={40} style={{ color: "var(--secondary-color)" }} />
                        </button>
                    </div>
                    <div className={styles.leftSection2}>
                        BUSINESS UNIT
                    </div>

                    <div className={styles.midSection}>
                        <button className={styles.buttonFooter} disabled={isRealtime} onClick={() => { generateData() }}>
                            <TbRefreshDot />
                        </button>

                        <div className={styles.inputGroup}>
                            <label htmlFor="startDate">START DATE :</label>
                            <input
                                type="date"
                                value={formatDate(filterDate.start_date, "yyyy-MM-dd")}
                                onChange={(e) =>
                                    setFilterDate((prev) => ({
                                        ...prev,
                                        start_date: new Date(e.target.value),
                                    }))
                                }
                                className={styles.dateInput}
                                disabled={isRealtime}
                                style={{
                                    border: "0px solid black",
                                    borderRadius: "5px",
                                    backgroundColor: isRealtime ? "#eee" : "white",
                                    color: "var(--header-color-hover)",
                                }}
                            />
                        </div>

                        <div className={styles.inputGroup}>
                            <label htmlFor="endDate">END DATE :</label>
                            <input
                                type="date"
                                value={formatDate(filterDate.end_date, "yyyy-MM-dd")}
                                onChange={(e) =>
                                    setFilterDate((prev) => ({
                                        ...prev,
                                        end_date: new Date(e.target.value),
                                    }))
                                }
                                className={styles.dateInput}
                                disabled={isRealtime}
                                style={{
                                    border: "0px solid black",
                                    borderRadius: "5px",
                                    backgroundColor: isRealtime ? "#eee" : "white",
                                    color: "var(--header-color-hover)",
                                }}
                            />
                        </div>

                        <div className={styles.switchGroup}>
                            <label htmlFor="realtime">Realtime</label>
                            <label className={styles.switch}>
                                <input
                                    type="checkbox"
                                    id="realtime"
                                    checked={isRealtime}
                                    onChange={handleToggle}
                                />
                                <span className={styles.slider}></span>
                            </label>
                        </div>
                    </div>
                </div>
            </div>

            {/* Body */}
            <div className={styles.cardDetailContainer}>

                {/* Body Left */}
                <div className={styles.gridLeft}>
                    <div className={styles.gridLeftTop}>
                        {level1Data.business_unit}
                    </div>

                    <div className={styles.gridLeftMid}>
                        <div className={styles.gridLeftMidContainer}>

                            {/* Item Pressure */}
                            <div className={styles.gridLeftItem} key="pressure">
                                <div className={styles.gridLeftItemHeader}>
                                    <div>Pressure</div>
                                </div>
                                <div className={styles.gridLeftItemBody}>
                                    <div className={styles.itemBodyValue}>
                                        <div>{level1Data.ool_pressure}</div>
                                        <div>OOL</div>
                                    </div>
                                    <div className={styles.itemBodyValue}>
                                        <div>{(level1Data.machine_ool_pressure ?? []).length}</div>
                                        <div>Machine OOL</div>
                                    </div>
                                </div>
                            </div>

                            {/* Item Vibration */}
                            <div className={styles.gridLeftItem} key="vibration">
                                <div className={styles.gridLeftItemHeader}>
                                    <div>Vibration</div>
                                </div>
                                <div className={styles.gridLeftItemBody} style={{ gridTemplateColumns: 'repeat(3, 1fr)' }}>
                                    <div className={styles.itemBodyValue}>
                                        <div>{level1Data.ool_vibration}</div>
                                        <div>OOL Vibration</div>
                                    </div>
                                    <div className={styles.itemBodyValue}>
                                        <div>{level1Data.ool_temperature}</div>
                                        <div>OOL Temperature</div>
                                    </div>
                                    <div className={styles.itemBodyValue}>
                                        <div>{(level1Data.machine_ool_vibration ?? []).length}</div>
                                        <div>Machine OOL</div>
                                    </div>
                                </div>
                            </div>

                            {/* Item Following Error */}
                            <div className={styles.gridLeftItem} key="following-error">
                                <div className={styles.gridLeftItemHeader}>
                                    <div>Following Error</div>
                                </div>
                                <div className={styles.gridLeftItemBody}>
                                    <div className={styles.itemBodyValue}>
                                        <div>{level1Data.ool_following_error}</div>
                                        <div>OOL</div>
                                    </div>
                                    <div className={styles.itemBodyValue}>
                                        <div>{(level1Data.machine_ool_following_error ?? []).length}</div>
                                        <div>Machine OOL</div>
                                    </div>
                                </div>
                            </div>

                            {/* Item Centerline */}
                            <div className={styles.gridLeftItem} key="centerline">
                                <div className={styles.gridLeftItemHeader}>
                                    <div>Centerline</div>
                                </div>
                                <div className={styles.gridLeftItemBody} style={{ gridTemplateColumns: 'repeat(3, 1fr)' }}>
                                    <div className={styles.itemBodyValue}>
                                        <div>{level1Data.centerline_green}</div>
                                        <div>Normal</div>
                                    </div>
                                    {/* <div className={styles.itemBodyValue}>
                                        <div>{level1Data.centerline_yellow}</div>
                                        <div>Warning</div>
                                    </div> */}
                                    <div className={styles.itemBodyValue}>
                                        <div>{level1Data.centerline_red}</div>
                                        <div>Alarm</div>
                                    </div>
                                    <div className={styles.itemBodyValue}>
                                        <div>{(level1Data.machine_ool_centerline ?? []).length}</div>
                                        <div>OOL</div>
                                    </div>
                                </div>
                            </div>

                        </div>
                    </div>

                    <div className={styles.gridLeftBottom}>
                        <div>Machine OOL</div>
                        <div>{level1Data.machine_ool.length}</div>
                    </div>
                </div>

                {/* Body Right */}
                <div className={styles.gridRight}>
                    {luData.map((item, index) => {
                        const data = tableData[`${item.link_up_id}`]
                        const foll = tableDataFoll[`${item.link_up_id}`]
                        const centerline = tableDataCenterline[`${item.link_up_id}`]

                        let merged: number[] = []
                        if (data) {
                            merged = merged.concat(data.machine_ool_pressure)
                            merged = merged.concat(data.machine_ool_vibration)
                        }
                        if (foll) {
                            merged = merged.concat(foll.machine_ool_following_error)
                        }
                        if (centerline) {
                            merged = merged.concat(centerline.centerline_id_ool)
                        }
                        const machine_ool = Array.from(new Set(merged))

                        return <div key={item.link_up_id} className={styles.gridItem}
                            onClick={() => {
                                if (data || foll) {
                                    navigate(`/dashboard/l3/${item.link_up_id}`, {
                                        state: {
                                            link_up: {
                                                link_up: item.link_up,
                                                link_up_id: item.link_up_id,
                                            },
                                            start_date: filterDate.start_date,
                                            end_date: filterDate.end_date,
                                            realtimeState: isRealtime
                                        },
                                    })
                                }
                            }}>

                            <div className={styles.gridItemHeader}>
                                <div>{item.link_up}</div>
                            </div>

                            <div className={styles.gridItemBody}>

                                {data != undefined
                                    ? <>
                                        <div className={styles.cardSubItem}>
                                            <div className={styles.cardSubItemHeader}>
                                                Pressure
                                            </div>
                                            <div className={styles.cardSubItemBody}>
                                                <div className={`${styles.itemValue} ${getStatusOOL(data.ool_pressure, item)}`}>
                                                    <h2>{data.ool_pressure ?? 0}</h2>
                                                    <h3>OOL</h3>
                                                </div>
                                                <div className={`${styles.itemValue} ${getStatusOOL(data.machine_ool_pressure.length, item)}`}>
                                                    <h2>{data.machine_ool_pressure.length}</h2>
                                                    <h3>Machine OOL</h3>
                                                </div>
                                            </div>
                                            {data.sensor_pressure_total > 0 && (
                                                <div className={styles.cardSubItemFooter}>
                                                    <div>Connect</div>
                                                    <div>{data.sensor_pressure_connected} / {data.sensor_pressure_total}</div>
                                                </div>
                                            )}
                                        </div>

                                        <div className={styles.cardSubItem}>
                                            <div className={styles.cardSubItemHeader}>
                                                Vibration
                                            </div>
                                            <div className={styles.cardSubItemBody}>
                                                <div className={`${styles.itemValue} ${getStatusOOL(data.ool_vibration, item)}`}>
                                                    <h2>{data.ool_vibration ?? 0}</h2>
                                                    <h3>Vibration OOL</h3>
                                                </div>
                                                <div className={`${styles.itemValue} ${getStatusOOL(data.ool_temperature, item)}`}>
                                                    <h2>{data.ool_temperature ?? 0}</h2>
                                                    <h3>Temperature OOL</h3>
                                                </div>
                                                <div className={`${styles.itemValue} ${getStatusOOL(data.machine_ool_vibration.length, item)}`}>
                                                    <h2>{data.machine_ool_vibration.length ?? 0}</h2>
                                                    <h3>Machine OOL</h3>
                                                </div>
                                            </div>
                                            {data.sensor_vibration_total > 0 && (
                                                <div className={styles.cardSubItemFooter}>
                                                    <div>Connect</div>
                                                    <div>{data.sensor_vibration_connected} / {data.sensor_vibration_total}</div>
                                                </div>
                                            )}
                                        </div>
                                    </>
                                    : <></>}

                                {foll != undefined
                                    ? <>
                                        <div className={styles.cardSubItem}>
                                            <div className={styles.cardSubItemHeader}>
                                                Following Error
                                            </div>
                                            <div className={styles.cardSubItemBody}>
                                                <div className={`${styles.itemValue} ${getStatusOOL(foll.ool_following_error, item)}`}>
                                                    <h2>{foll.ool_following_error}</h2>
                                                    <h3>OOL</h3>
                                                </div>
                                                <div className={`${styles.itemValue} ${getStatusOOL(foll.machine_ool_following_error.length, item)}`}>
                                                    <h2>{foll.machine_ool_following_error.length}</h2>
                                                    <h3>Machine OOL</h3>
                                                </div>
                                            </div>
                                        </div>
                                    </>
                                    : <></>}

                                {centerline != undefined
                                    ? <>
                                        <div className={styles.cardSubItem}>
                                            <div className={styles.cardSubItemHeader}>
                                                Centerline
                                            </div>
                                            <div className={styles.cardSubItemBody}>
                                                <div className={styles.itemValue}>
                                                    <h2>{centerline.centerline_green}</h2>
                                                    <h3>Normal</h3>
                                                </div>
                                                {/* <div className={styles.itemValue}>
                                                    <h2>{centerline.centerline_yellow}</h2>
                                                    <h3>Warning</h3>
                                                </div> */}
                                                <div className={styles.itemValue}>
                                                    <h2>{centerline.centerline_red}</h2>
                                                    <h3>Alarm</h3>
                                                </div>
                                                <div className={`${styles.itemValue} ${getStatusOOLCenterline(centerline.centerline_id_ool.length, centerline)}`}>
                                                    <h2>{centerline.centerline_id_ool.length}</h2>
                                                    <h3>OOL</h3>
                                                </div>
                                            </div>
                                        </div>
                                    </>
                                    : <></>}
                            </div>

                            {data || foll
                                ? <div className={styles.gridItemFooter}>
                                    <div>Summary Machine OOL</div>
                                    <div>{machine_ool.length}</div>
                                </div>
                                : <></>}
                        </div>
                    })}
                </div>

            </div>
        </div>
    )
}
